qa_register_test("FIXTURE_001","regression","high","Valid synthetic abundance data pass structural checks",function(){d<-utils::read.csv(file.path(QA_ROOT,"QualityAssurance","fixtures","valid","minimal_abundance.csv"),check.names=FALSE);qa_expect_true(nrow(d)>=30 && sum(grepl("Sample",names(d),fixed=TRUE))==12)})
qa_register_test("VALID_001","regression","high","Duplicate sample fixture is detected",function(){d<-utils::read.csv(file.path(QA_ROOT,"QualityAssurance","fixtures","invalid","duplicated_samples.csv"),check.names=FALSE);qa_expect_true(anyDuplicated(names(d))>0 || anyDuplicated(d[[1]])>0,"Fixture contains no duplicate")})
qa_register_test("EDGE_001","regression","medium","UTF-8 fixture preserves special characters",function(){d<-utils::read.csv(file.path(QA_ROOT,"QualityAssurance","fixtures","edge_cases","special_characters.csv"),fileEncoding="UTF-8",check.names=FALSE);qa_expect_true(any(grepl("ñ|á|µ",unlist(d))))})
